import java.util.ArrayList;
import java.util.HashMap;
import sailpoint.object.Rule;

// The name of the rule to be executed
String ruleToExecuteName = "BSF Dynamic SMS Integration Rule";

// Prepare values for arguments
String eventSource = "IGA";
String smsMessage = "Welcome to BSF";
String smsSender = "BSFSystem";
String priority = "3";
String smsType = "2";

// Prepare recipients list
ArrayList recipients = new ArrayList();

// Example recipient 1
HashMap recipient1 = new HashMap();
recipient1.put("customerId", "123456");
recipient1.put("notificationMethod", "10000");
recipient1.put("notificationLanguage", "en_US");
recipient1.put("notificationEncoding", "UTF-8");
recipient1.put("mobileNumber", "+911234567890");

// Additional parameters (optional)
HashMap parameters = new HashMap();
parameters.put("firstname", "Rohan");
parameters.put("creds", "pass@5678");
recipient1.put("parameters", parameters);

recipients.add(recipient1);

// Get the Rule object from the context
Rule integrationRule = context.getObjectByName(Rule.class, ruleToExecuteName);

// Call the rule via context.runRule()
HashMap args = new HashMap();
args.put("eventSource", eventSource);
args.put("smsMessage", smsMessage);
args.put("smsSender", smsSender);
args.put("recipients", recipients);
args.put("priority", priority);
args.put("smsType", smsType);

try {
    if (integrationRule != null) {
        String result = (String) context.runRule(integrationRule, args);
        log.error("SMS Integration Result: " + result);
    } else {
        log.error("Rule '" + ruleToExecuteName + "' not found.");
        return "ERROR: Rule not found";
    }

} catch (Exception e) {
    log.error("Error executing SMS integration rule: " + e.getMessage(), e);
    return "ERROR: " + e.getMessage();
}

return "Success";
